///<reference types="jquery" />
import { XWindow } from '../flame';
import { Parked } from './types';

export namespace util {
    /**
     * 深拷贝对象，通过内部缓存处理循环引用。
     * @param value 需要拷贝的值
     * @return 拷贝后的新对象
     */
    export function deepClone(value): any {
        const cache = new Map();
        function _deepClone(value) {
            if (typeof value !== 'object' || value === null) {
                return value;
            }
            if (cache.has(value)) {
                return cache.get(value);
            }
            const result = Array.isArray(value) ? [] : {};
            cache.set(value, result);
            for (const key in value) {
                result[key] = _deepClone(value[key]);
            }

            return result;
        }

        return _deepClone(value);
    }
    /**
     * 判空：null 或 undefined 返回 true。
     * @param o 待判定值
     * @return 是否为 null/undefined
     */
    export function isNull(o: any): boolean {
        if (o == null || typeof o == 'undefined') {
            return true;
        } else {
            return false;
        }
    }

    /**
     * 判断字符串是否符合平台内部 OID 格式。
     *
     * 匹配格式：`OR:package.ClassName:id`，其中 `OR:` 前缀可选，
     * 类名部分支持多层包名（以 `.` 分隔），id 部分为纯数字。
     *
     * @param o 待检测的任意值。
     * @returns 匹配 OID 格式时返回 `true`。
     *
     * @example
     * ```ts
     * isOid('OR:xw.context.Folder:1121')  // true
     * isOid('xw.auths.entity.XUser:42')   // true
     * isOid('hello')                       // false
     * ```
     */
    export function isOid(o: any): boolean {
        if (o instanceof Object) {
            return false;
        }
        if (o == null || o == '' || typeof o == 'undefined') {
            return false;
        }
        return !!(o as string).match('(OR:)?([a-z0-9A-Z]+\\.)+[a-z0-9A-Z]+(:[0-9]+)');
    }

    /**
     * 判空（含空字符串）：null / undefined / '' / 纯空白字符串返回 true。
     * @param o 待判定值
     * @return 是否为空白
     */
    export function isBlank(o: any): boolean {
        if (o == null || o == '' || typeof o == 'undefined') {
            return true;
        } else if (o instanceof Object) {
            return false;
        } else if (typeof o == 'string') {
            let s = o.replace(/^\s+/g, '').replace(/\s+$/g, '');
            if (s == '') {
                return true;
            }
        }
        return false;
    }

    /**
     * 拼接字符串数组，过滤掉 undefined 项后连接。
     * @param o 字符串数组
     * @return 拼接后的字符串
     */
    export function concat(o: Array<string>): string {
        if (o) {
            return o.filter((item) => item != void 0).join('');
        } else {
            return '';
        }
    }

    /**
     * 判定值为 undefined。
     * @param o 待判定值
     * @return 是否为 undefined
     */
    export function isUndefined(o: any) {
        return o === void 0;
    }

    /**
     * 计算元素 o 相对于祖先元素 p（或文档根）的偏移坐标。
     *
     * <p>沿 offsetParent 链逐级累加 offsetTop / offsetLeft，
     * 当 p 为 null/undefined 时累加到文档根（offsetParent 为 null）。</p>
     *
     * @param o 目标元素
     * @param p 参考祖先元素，为 null 时相对于文档根
     * @returns { top, left } 偏移量（像素）
     */
    export function getPosition(o: HTMLElement, p: HTMLElement): { top: number; left: number } {
        let t = 0, l = 0;
        // 沿 offsetParent 链累加，遇到 p 或到达文档根时停止
        while (o && o != p) {
            t += o.offsetTop;
            l += o.offsetLeft;
            o = o.offsetParent as HTMLElement;
        }
        return { top: t, left: l };
    }

    /**
     * 通过「点分隔路径名」获取全局作用域中的函数引用。
     *
     * 常用于将 beforeJS / afterJS 字符串配置解析为实际可调用的函数。
     * 支持任意层级的命名空间，如 `"flame.submitForm"` 或 `"myLib.utils.foo"`。
     *
     * @param name 函数全路径名，以 `.` 分隔命名空间。
     * @param context       查找根对象，在浏览器环境默认为 `window`，在非浏览器环境回退到 `globalThis`。
     * @returns 找到的函数引用；若路径中任一层级不存在则返回 `undefined`。
     *
     * @example
     * ```ts
     * const fn = getFunctionByName('flame.reloadDataGrid');
     * if (fn) fn('myGrid', { oid: '123' });
     * ```
     */
    export function getFunction(name: string, context?: any): any {
        if (typeof window == 'undefined') {
            context = context || (globalThis as any);
        } else {
            context = context || window;
        }

        const namespaces = name.split('.');
        const functionToExecute = namespaces.pop();
        for (let i = 0; i < namespaces.length; i++) {
            context = context[namespaces[i]];
        }
        if (context) {
            return context[functionToExecute!];
        }
        return undefined;
    }

    /**
     * 根据停放位置设置元素的绝对定位样式。
     * @param el 目标元素
     * @param parked 停放位置：fit/top/bottom/left/right/center
     */
    export function setPosition(el: HTMLElement, parked: Parked) {
        switch (parked) {
            case 'fit':
                el.style.position = 'absolute';
                el.style.inset = '0px';
                break;
            case 'top':
                el.style.position = 'absolute';
                el.style.top = '0px';
                el.style.removeProperty('bottom');
                break;
            case 'bottom':
                el.style.position = 'absolute';
                el.style.bottom = '0px';
                el.style.removeProperty('top');
                break;
            case 'left':
                el.style.position = 'absolute';
                el.style.left = '0px';
                el.style.removeProperty('right');
                break;
            case 'right':
                el.style.position = 'absolute';
                el.style.right = '0px';
                el.style.removeProperty('left');
                break;
            case 'center':
                el.style.position = 'absolute';
                const parent = el.parentElement || (el.parentNode instanceof ShadowRoot ? (el.parentNode as ShadowRoot).host as HTMLElement : null);
                if (parent) {
                    const left = (parent.offsetWidth - el.offsetWidth) / 2;
                    const top = (parent.offsetHeight - el.offsetHeight) / 2;
                    el.style.left = (left < 0 ? 0 : left) + 'px';
                    el.style.top = (top < 0 ? 0 : top) + 'px';
                    el.style.removeProperty('right');
                    el.style.removeProperty('bottom');
                }
                break;
            default:
                break;
        }
    }

    /**
     * 从数组或普通对象中移除元素 / 属性。
     *
     * 操作规则：
     * - **数组**：若 `e` 为数字，按下标删除；若 `e` 为普通对象 `{key: value}`，
     *   查找第一个匹配该键值的元素并删除。
     * - **对象**：删除 `e` 对应的属性（通过 `Reflect.has` 检测存在性）。
     *
     * @param o 目标数组或普通对象。
     * @param e 下标（数字）、匹配条件对象 `{key: value}`、或属性名字符串。
     * @returns 成功移除时返回 `true`，否则返回 `false`。
     *
     * @example
     * ```ts
     * const arr = [{id: 1}, {id: 2}, {id: 3}];
     * removeElement(arr, {id: 2});  // true → arr = [{id: 1}, {id: 3}]
     *
     * const obj = { a: 1, b: 2 };
     * removeElement(obj, 'a');      // true → obj = { b: 2 }
     * ```
     */
    export function removeElement(o: any, e: any): boolean {
        if (o === undefined || e === undefined) {
            return false;
        }
        if (Array.isArray(o)) {
            let idx = -1;
            if (isNaN(e)) {
                for (const i in o) {
                    const item = o[i];
                    if (item === undefined) {
                        continue;
                    }
                    let ok = true;
                    for (const [key, value] of Object.entries(e)) {
                        if (item[key] !== value) {
                            ok = false;
                            break;
                        }
                    }
                    if (ok) {
                        idx = parseInt(i);
                        break;
                    }
                }
            } else {
                if (e >= o.length) {
                    return false;
                }
                if (e > -1) {
                    idx = e;
                }
            }
            if (idx > -1) {
                o.splice(idx, 1);
                return true;
            }
            return false;
        }
        if (Reflect.has(o, e)) {
            delete o[e];
            return true;
        }
        return false;
    }

    /**
     * 为元素添加 CSS 类名（避免重复添加）。
     * @param el 目标元素
     * @param name 类名
     */
    export function addClass(el: HTMLElement, name: string) {
        if (!el.classList.contains(name)) {
            el.classList.add(name);
        }
    }

    /**
     * 从元素移除 CSS 类名。
     * @param el 目标元素
     * @param name 类名
     */
    export function removeClass(el: HTMLElement, name: string) {
        if (el.classList.contains(name)) {
            el.classList.remove(name);
        }
    }
    /**
     * 将字符串首字母转为大写。
     * @param text 输入字符串
     * @return 首字母大写的字符串
     */
    export function uppercaseFirstLetter(text: string) {
        return text.charAt(0).toUpperCase() + text.slice(1);
    }

    /**
     * 获取当前元素之后的所有兄弟元素。
     * @param el 起始元素
     * @return 后续兄弟元素数组
     */
    export function nextAll(el: Element) {
        const siblings: Element[] = [];
        while (el.nextElementSibling) {
            siblings.push(el.nextElementSibling);
            el = el.nextElementSibling;
        }
        return siblings;
    }

    /**
     * 基于 EasyUI 的方式加载远程内容——使用 jQuery.load() 发起 AJAX 请求并
     * 自动执行响应中的<script>标签（包括带 src 的外部脚本）。
     *
     * 适用场景：主页面已通过 EasyUI 模板加载了框架脚本（jQuery、EasyUI 等），
     * 页面重新加载时会重复执行这些脚本；若页面使用了 begin::easyUI 模板，
     * 内部 EasyUI 组件依赖的插件（如 flame.cookie.js）也会被重新加载。
     *
     * @param selector 目标元素或 CSS 选择器
     * @param href 加载的 URL
     * @param callback 加载完成后的回调
     */
    export function euiLoad(selector: any, href: string, callback?: any) {
        if (isBlank(selector) || isBlank(href)) return;
        (($) => {
            if ($.parser && $.parser.auto == false) {
                $.parser.auto = true;
            }
            $(selector).load(href, () => {
                if (callback) {
                    callback();
                }
            });
        })(window.jQuery);
    }

    /**
     * 基于 XUI 的方式加载远程内容——使用 fetch API 获取内容，通过 innerHTML
     * 插入 DOM。浏览器不会执行 innerHTML 中的脚本，因此避免了框架脚本被重新
     * 执行导致页面状态异常。内联脚本通过手动创建 script 元素执行。
     *
     * 适用场景：加载的页面使用了 begin::easyUI 等包含框架脚本的模板，
     * 但主页面已经加载过这些脚本，不需要再次执行。
     *
     * @param selector 目标元素或 CSS 选择器
     * @param href 加载的 URL
     * @param callback 加载完成后的回调
     */
    export function xuiLoad(selector: any, href: string, callback?: any) {
        if (isBlank(selector) || isBlank(href)) return;

        const target = typeof selector === 'string' ? document.querySelector(selector) as HTMLElement : selector as HTMLElement;
        if (!target) return;

        window.fetch(href).then(response => response.text()).then(html => {
            const temp = document.createElement('div');
            temp.innerHTML = html;
            const body = temp.querySelector('body');
            const content = body ? body.innerHTML : html;

            target.innerHTML = content;

            /**
             * 执行内联脚本：target.innerHTML 插入的 <script> 不会执行（浏览器安全机制），
             * 需用 createElement 新建可执行副本，replaceWith 替换原始标签触发执行。
             * 同时 replaceWith 确保 DOM 中只有一份副本，避免后续 $.parser.parse()
             * 重构 DOM 时残留的原始标签被浏览器再次解析导致二次执行。
             **/
            target.querySelectorAll('script').forEach(s => {
                if (!s.getAttribute('src')) {
                    const script = document.createElement('script');
                    script.textContent = s.textContent;
                    if (s.type) {
                        script.type = s.type;
                    }
                    s.replaceWith(script);
                }
            });

            const $ = (window as any).jQuery;
            if ($?.parser) {
                if ($.parser.auto === false) $.parser.auto = true;
                $.parser.parse(target);
            }

            if (callback) callback();
        }).catch(error => {
            console.error(`xuiLoad: failed to load "${href}"`, error);
        });
    }

    /**
     * 通过 jQuery 触发指定事件。
     * @param el 目标元素
     * @param event 事件名称
     */
    export function trigger(el: HTMLElement, event: string) {
        (($) => {
            $(el).trigger(event);
        })(window.jQuery);
    }

    /**
     * 将 JSON 格式字符串（不含首尾花括号）解析为对象。
     * 例：'key: "value", num: 1' → { key: "value", num: 1 }
     * @param str 不含花括号的 JSON 字符串
     * @return 解析后的对象，空则返回 undefined
     */
    export function unsafeJson(str: string) {
        if (isBlank(str)) return;

        return new Function('return ' + str)();
    }

    /**
     * 全局替换字符串中的匹配项。
     * @param str 原始字符串
     * @param o 替换规则：单个匹配串或 { o: 匹配串, n: 替换串 } 数组
     * @param n 替换串（o 为字符串时使用）
     * @return 替换后的字符串
     */
    export function replaceAll(str: string, o: string | Array<{ o: string; n: string }>, n?: string) {
        if (isBlank(str)) return str;

        if (o instanceof String) {
            if (isBlank(o) || isBlank(n)) return str;
            else str = str.replace(new RegExp(o as string, 'gm'), n as string);
        } else if (o instanceof Array) {
            for (const val of o) {
                str = str.replace(new RegExp(val.o, 'gm'), val.n);
            }
        }
        return str;
    }

    /**
     * 批量设置元素的行内样式。
     * @param el 目标元素
     * @param values 样式键值对
     */
    export function setStyle(el: HTMLElement, values: any) {
        if (el && values) {
            for (const key in values) {
                if (key) {
                    el.style.setProperty(key, values[key]);
                }
            }
        }
    }

    /**
     * 解析 URL，分离基础 URI 和查询参数。
     * @param url 完整 URL
     * @return { uri, params } 基础地址和参数对象
     */
    export function parseUrl(url: string) {
        if (isBlank(url)) {
            return { uri: '', params: {} };
        } else {
            const i = url.indexOf('?');
            if (i > 0) {
                const uri = url.substring(0, i);
                const query = url.substring(i + 1);
                const params: { [key: string | number | symbol]: string } = {};
                for (const item of query.split('&')) {
                    const j = item.indexOf('=');
                    const name = item.substring(0, j);
                    const value = item.substring(j + 1);
                    params[name] = value;
                }
                return { uri: uri, params: params };
            } else {
                return { uri: url, params: {} };
            }
        }
    }

    /**
     * 将参数合并到 URL 中，生成带查询参数的完整地址。
     * @param url 基础 URL（可选含已有参数）
     * @param params 需合并的查询参数
     * @return 合并后的完整 URL
     */
    export function marginUrl(url: string | undefined, params: { [key: string | number | symbol]: string }) {
        if (isBlank(url)) {
            return '';
        } else {
            const object = parseUrl(url == void 0 ? '' : url);
            if (typeof params == 'object') {
                object.params = Object.assign(object.params, params);
            }

            let result = object.uri;
            let first: boolean = true;
            for (const key in object.params) {
                if (first) {
                    result = result + '?' + key + '=' + object.params[key];
                    first = false;
                } else {
                    result = result + '&' + key + '=' + object.params[key];
                }
            }
            return result;
        }
    }

    /**
     * 按选择器查找已有窗口，设置属性和 URL 后显示。
     * @param selector 窗口的 CSS 选择器
     * @param params 窗口参数 { url, options, style }
     */
    export function openWindow(selector: string, params: { url: string; options: string; style: string }) {
        if (isBlank(selector)) return;
        const win = document.querySelector(selector) as XWindow;
        if (win) {
            if (params && params.options) {
                win.setAttribute('x-options', params.options);
            }
            if (params && params.style) {
                win.setAttribute('style', params.style);
            }
            if (params && !isBlank(params.url)) {
                win.iframe(params.url);
            }
            win.show();
        }
    }

    /**
     * 动态创建 x-window 元素并添加到页面中。
     * @param params 窗口参数 { parent, id, url, options, style }
     * @return 创建的窗口元素
     */
    export function newWindow(params: { parent?: string; id?: string; url: string; options: string; style: string }) {
        const win = document.createElement('x-window') as XWindow;
        if (win) {
            let bool = false;
            if (params) {
                if (params.parent) {
                    const parent = document.querySelector(params.parent);
                    if (parent) parent.appendChild(win);
                    else bool = true;
                } else {
                    bool = true;
                }
                if (params.id) win.setAttribute('style', params.id);
                if (params.options) {
                    win.setAttribute('x-options', params.options + ',destroy:true');
                }
                if (params.style) win.setAttribute('style', params.style);
                if (!isBlank(params.url)) win.iframe(params.url);
            } else {
                win.setAttribute('x-options', 'destroy:true');
            }

            if (bool) document.body.appendChild(win);
        }

        return win;
    }

    // ── 日期格式化 ────────────────────────────────────────────────────────────

    /**
     * DateBox 美式日期格式化：`M/d/yyyy`。
     * @param date 日期对象。
     * @returns 格式化后的日期字符串，如 `"6/13/2026"`。
     */
    export function datebox$en_US(date: Date): string {
        return (date.getMonth() + 1) + '/' + date.getDate() + '/' + date.getFullYear();
    }

    /**
     * DateBox 中式日期格式化：`yyyy/M/d`。
     * @param date 日期对象。
     * @returns 格式化后的日期字符串，如 `"2026/6/13"`。
     */
    export function datebox$zh_CN(date: Date): string {
        return date.getFullYear() + '/' + (date.getMonth() + 1) + '/' + date.getDate();
    }

    /**
     * DateBox 本地化日期格式化——根据 locale 标识选择对应的格式化函数。
     *
     * 规则：
     * - 尝试通过 `util.getFunctionByName('datebox$' + local)` 查找 locale 对应的函数。
     * - 若找到则调用之，否则回退到 `datebox$en_US` 作为默认格式。
     *
     * @param date  日期对象。
     * @param local locale 标识，如 `"zh_CN"` / `"en_US"`。
     * @returns 格式化后的日期字符串。
     */
    export function datebox$local(date: Date, local: string): string {
        const fn = util.getFunction('datebox$' + local);
        return fn ? fn(date) : datebox$en_US(date);
    }

    // ── CSRF ──────────────────────────────────────────────────────────────────

    /**
     * 从浏览器 cookie 中读取 CSRF Token。
     *
     * @returns CSRF Token 字符串（`XSRF-TOKEN`），若 cookie 中不存在则返回 `undefined`。
     *
     * @remarks
     * 所有 POST / GET 请求通过 `queryParams._csrf` 携带此 token，
     * 以满足 Spring Security 的 CSRF 防护要求。
     */
    export function getCsrf(): string | undefined { return (jQuery as any).cookie('XSRF-TOKEN'); }

    /**
     * 解析当前页面 URL 的查询参数（query string）。
     *
     * 优先解析 {@link window.location.search}，当其为空时（如 hash 路由场景），
     * 自动从 {@link window.location.hash} 中提取 `?` 之后的查询字符串，
     * 确保在 hash 路由模式（如 `/XWorx#/page?a=1&b=hello`）下也能正确获取参数。
     *
     * @returns 参数键值对，值已由 {@link URLSearchParams} 自动解码。
     *
     * @example
     * ```ts
     * // URL = /page?a=1&b=hello
     * getURLParameter() // { a: '1', b: 'hello' }
     *
     * // URL = /XWorx#/page?a=1&b=hello（hash 路由）
     * getURLParameter() // { a: '1', b: 'hello' }
     * ```
     */
    export function getURLParameter(): Record<string, any> {
        const result: Record<string, any> = {};

        let search = window.location.search;
        // 当标准查询字符串为空时（hash 路由场景），从 hash 中提取查询参数
        if (!search || search === '' || search === '?') {
            const hash = window.location.hash;
            const queryIndex = hash.indexOf('?');
            if (queryIndex > -1) {
                search = hash.substring(queryIndex);
            }
        }

        if (search) {
            const searchParams = new URLSearchParams(search);
            searchParams.forEach((value, key) => {
                if (key) {
                    result[key] = value;
                }
            });
        }
        return result;
    }

    /**
     * 设置 URL 查询参数，与 {@link getURLParameter} 的读取逻辑对称。
     *
     * 优先写入 hash 的查询字符串（hash 路由场景），若 hash 不存在则写入标准查询字符串。
     * 使用 `replaceState` 更新 URL，不触发页面刷新也不产生历史记录。
     *
     * @param key   参数名
     * @param value 参数值
     *
     * @example
     * ```typescript
     * // URL = /XWorx#/page?a=1
     * setURLParameter('tab', 'detail') // /XWorx#/page?a=1&tab=detail
     *
     * // URL = /page?a=1
     * setURLParameter('tab', 'detail') // /page?a=1&tab=detail
     * ```
     */
    export function setURLParameter(key: string, value: string): void {
        const url = new URL(window.location.href);
        const hash = url.hash;

        if (hash) {
            const hashBody = hash.substring(1);
            const qIdx = hashBody.indexOf('?');
            const path = qIdx >= 0 ? hashBody.substring(0, qIdx) : hashBody;
            const params = new URLSearchParams(qIdx >= 0 ? hashBody.substring(qIdx + 1) : '');
            params.set(key, value);
            url.hash = path + '?' + params.toString();
        } else {
            url.searchParams.set(key, value);
        }

        window.history.replaceState({}, '', url);
    }

    /**
     * 生成 UUID 格式的全局唯一标识符。
     * @returns UUID 字符串，如 `"a3f2b1c4-d5e6-7890-abcd-ef1234567890"`
     */
    export function guid(): string {
        function S4() {
            return (((1 + Math.random()) * 0x10000) | 0).toString(16).substring(1);
        }
        return (S4() + S4() + '-' + S4() + '-' + S4() + '-' + S4() + '-' + S4() + S4() + S4());
    }

    /**
     * 生成随机 ID，用于动态创建 DOM 元素时避免 id 冲突。
     *
     * @param id 可选前缀，如 `"xwx_button_menu"`。若提供则返回 `prefix + 随机数`。
     * @returns 随机数字（0~999999），如有前缀则拼接。
     *
     * @remarks
     * 用于 `loadButtonMenu` 等需要动态创建唯一 id 的场景。
     */
    export function randomId(id?: string): any {
        const r = Math.trunc(Math.random() * 1000000);
        return id ? id + r : r;
    }

    /**
     * 将输入转为对象。
     *
     * - 若已是 `object` 类型则直接返回。
     * - 若为 JSON 字符串则调用 `JSON.parse` 解析，解析失败时返回 `{}`。
     * - 其他类型（如数字）原样返回。
     *
     * @param data 任意输入，通常为 JSON 字符串或已解析的对象。
     * @returns 解析后的对象。
     */
    export function toObject(data: any): any {
        if (typeof data == 'string') {
            try {
                return JSON.parse(data);
            } catch (e) {
                console.error(e);
                return {};
            }
        }
        if (typeof data == 'object') {
            return data;
        }
        return data;
    }

    /**
     * 通过 `new Function()` 动态执行一段 JavaScript 脚本。
     *
     * 常用于执行 beforeJS / afterJS / onclick 回调字符串。
     * 脚本内部可通过 `p` / `o` / `result` / `data` / `args` 五个形参引用
     * 调用方传入的上下文对象。
     *
     * @param script 可执行的 JS 代码字符串。
     * @param p      传入脚本的上下文参数（所有五个形参接收同一个对象）。
     * @returns 脚本显式返回 `false` 时返回 `false`，否则返回 `true`。
     *
     * @remarks
     * 即使脚本返回 `undefined` 也视为成功（返回 `true`），只有显式 `return false`
     * 才会中止后续流程（如阻止弹窗打开或阻止表单提交）。
     */
    export function runScript(script: string, p: any): boolean {
        if (!isBlank(script)) {
            const result = new Function('p,o,result,data,args', script)(p, p, p, p, p);
            if (result) {
                return result;
            }
            if (result === false) {
                return false;
            }
            return true;
        }
        return true;
    }
}
