const btnCancel = `<svg data-action="cancel" viewBox="0 0 16 16" width="24" height="24" fill="#e53935" tabindex="0" role="button" style="cursor:pointer"><title>取消 (Esc)</title><path d="M4.646 4.646a.5.5 0 0 1 .708 0L8 7.293l2.646-2.647a.5.5 0 0 1 .708.708L8.707 8l2.647 2.646a.5.5 0 0 1-.708.708L8 8.707l-2.646 2.647a.5.5 0 0 1-.708-.708L7.293 8 4.646 5.354a.5.5 0 0 1 0-.708z"/></svg>`;
