/**
 * SysML 代码块行内编辑器（fence_sysml）。
 *
 * 在 x-markdown 编辑模式下，双击 ````sysml` 代码块进入此编辑器。
 * 文本编辑使用 CodeMirror 6，图形预览使用 antV X6（复用 sysml.ts 注册的节点形状）。
 *
 * ## 交互设计
 *
 * - **文本模式**（默认）— CodeMirror 6 编辑器直接编辑 SysML v2 源文本。
 *   Ctrl+Enter 提交，Escape 取消。
 * - **图类型选择**— 工具栏下拉框切换图类型（BDD/IBD/REQ/PAR/PKG/STMD/ACT），
 *   自动更新元数据行 `#!sysml <TYPE> "name"`。
 * - **图形预览**— 若全局 X6 库和 sysml 模块已加载，点击预览按钮在内嵌 mini 画布中
 *   实时渲染 SysML 图（使用 sysml.ts 注册的 sysml-block/sysml-composition 等自定义形状）。
 *
 * ## 数据格式
 *
 * `data-marked` 中存储的是完整的三反引号 fence block：
 * ```
 * ```sysml
 * package "MySystem" {
 *     block "Engine" { ... }
 * }
 * ```
 * ```
 */

import { EditorView, keymap, lineNumbers } from '@codemirror/view';
import { defaultKeymap } from '@codemirror/commands';
import { defaultHighlightStyle, syntaxHighlighting } from '@codemirror/language';
import { AbstractEditor, AbstractRenderer, type EditorCallbacks } from './abstract.editor.js';
import { sysml } from '../../sysml.js';

/** SysML 支持的图类型 */
const DIAGRAM_TYPES = ['BDD', 'IBD', 'REQ', 'PAR', 'PKG', 'STMD', 'ACT'];

/** X6 全局引用（由 <script> 标签注入） */
declare var X6: any;

/** X6 图缓存条目 */
export interface SysmlGraphEntry {
    graph: any;
    canvas: HTMLElement;
}

/**
 * SysML 预览渲染器（静态工具类）。
 *
 * 负责在 Markdown 预览模式下将 `fence_sysml` 块渲染为 X6 图。
 * 从 markdown.component.ts 中抽离，通过构造函数注入 renderRoot 和缓存 Map，
 * 保持 markdown 组件精简。
 *
 * @example
 * ```typescript
 * const renderer = new SysmlPreviewRenderer(renderRoot, sysmlGraphs, cmViews, previewTheme);
 * renderer.mount();
 * ```
 */
export class SysmlPreviewRenderer extends AbstractRenderer {

    /**
     * @param renderRoot  — ShadowRoot 或 HTMLElement，用于查询 .preview-pane
     * @param _sysmlGraphs — X6 图缓存 Map（data-id → {graph, canvas}），由宿主组件持有
     */
    constructor(
        renderRoot: HTMLElement | DocumentFragment | ShadowRoot,
        private _sysmlGraphs: Map<string, SysmlGraphEntry>,
    ) {
        super(renderRoot);
    }

    /**
     * 扫描所有 `fence_sysml` 块并渲染 X6 图。
     * 已挂载且 data-marked 未变的块跳过重建。
     * 若 sysml 模块或 X6 库未加载，回退为 CM6 只读视图。
     */
    mount(): void {
        const panes = this._previewPanes();
        if (panes.length === 0) return;

        const seen = new Set<string>();

        panes.forEach(pane => {
            const blocks = pane.querySelectorAll<HTMLElement>('[data-type="fence_sysml"]');
            blocks.forEach(block => {
                const dataId = block.getAttribute('data-id');
                if (!dataId) return;
                seen.add(dataId);

                const marked = block.getAttribute('data-marked') ?? '';

                // 已挂载且 marked 未变 → 跳过
                const existing = this._sysmlGraphs.get(dataId);
                if (existing && (existing.canvas as any).__sysmlMarked === marked) return;

                // 销毁旧图
                if (existing) {
                    existing.graph.dispose();
                    this._sysmlGraphs.delete(dataId);
                }

                // 从 data-marked 提取 SysML 代码
                const code = SysmlPreviewRenderer.extractCode(marked);
                if (!code.trim()) return;

                // 查找渲染占位元素
                const pre = block.querySelector<HTMLElement>('pre');
                if (!pre) return;

                // 检查 X6 是否可用：不可用时显示占位提示而非 CM6 回退
                const X6Lib = (window as any).X6;
                if (!X6Lib) {
                    if (!pre.querySelector('.sysml-placeholder')) {
                        pre.innerHTML = SysmlPreviewRenderer._placeholderHTML(code);
                    }
                    return;
                }

                // 确保 SysML 自定义形状已注册（首次调用时注册）
                sysml.ensureSysMLShapes();

                try {
                    const parser = new sysml.SysMLParser();
                    const diagram = parser.parse(code);

                    pre.innerHTML = '';
                    const canvas = document.createElement('div');
                    canvas.style.cssText = 'width:100%;min-height:300px;height:400px;';
                    (canvas as any).__sysmlMarked = marked;
                    pre.appendChild(canvas);

                    const graph = new X6Lib.Graph({
                        container: canvas,
                        width: canvas.clientWidth || 600,
                        height: 400,
                        resizing: false,
                        rotating: false,
                        panning: { enabled: true, modifiers: 'shift' },
                        mousewheel: { enabled: true, modifiers: 'ctrl', minScale: 0.5, maxScale: 2 },
                        grid: { size: 10, visible: true },
                        interacting: { nodeMovable: false, edgeLabelMovable: false, magnetConnectable: false },
                    });
                    graph.fromJSON(diagram);
                    graph.zoomToFit({ padding: 30, maxScale: 1.5 });

                    this._sysmlGraphs.set(dataId, { graph, canvas });
                } catch (err) {
                    console.warn('[x-markdown] SysML graph mount failed: %o', err);
                    pre.innerHTML = SysmlPreviewRenderer._placeholderHTML(code);
                }
            });
        });

        // 清理已脱离 DOM 的块对应的 X6 图
        for (const [dataId, entry] of this._sysmlGraphs) {
            if (!seen.has(dataId)) {
                entry.graph.dispose();
                this._sysmlGraphs.delete(dataId);
            }
        }
    }

    /**
     * 从 fence block 的 data-marked 中提取纯 SysML 代码（去掉 ```sysml 标记）。
     */
    static extractCode(marked: string): string {
        const lines = marked.replace(/\r\n/g, '\n').split('\n');
        while (lines.length > 0 && lines[lines.length - 1].trim() === '') lines.pop();
        if (lines.length === 0) return '';

        let start = 0;
        let end = lines.length;
        if (lines[0].trim().match(/^`{3,}\s*sysml\s*$/i)) start = 1;
        if (end > start && lines[end - 1].trim().match(/^`{3,}\s*$/)) end--;
        return lines.slice(start, end).join('\n');
    }

    /**
     * 生成 X6 不可用时的占位 HTML。
     * 显示 SysML 图标 + 提示文本 + 折叠的源代码，与 CM6 回退有明显视觉区分。
     */
    static _placeholderHTML(code: string): string {
        const escaped = code
            .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
        return `<div class="sysml-placeholder" style="
            background:#f5f5f5;border:1px dashed #bbb;border-radius:6px;
            padding:12px 16px;font-family:Arial,sans-serif;font-size:13px;
        ">
            <div style="display:flex;align-items:center;gap:8px;margin-bottom:8px;">
                <span style="font-size:20px;">▦</span>
                <span style="font-weight:bold;color:#1565c0;">SysML Diagram</span>
                <span style="color:#999;font-size:11px;">(X6 库未加载，预览不可用)</span>
            </div>
            <details style="cursor:pointer;">
                <summary style="color:#666;font-size:12px;">查看源代码</summary>
                <pre style="margin-top:4px;font-size:11px;max-height:200px;overflow:auto;white-space:pre-wrap;">${escaped}</pre>
            </details>
        </div>`;
    }
}

/**
 * SysML 代码块编辑器。
 *
 * 继承 {@link AbstractEditor}，实现 ````sysml` fence block 的行内编辑。
 * 编辑区使用 CodeMirror 6，工具栏提供图类型选择器和 X6 预览按钮。
 * 文本↔图形转换使用直接 import 的 sysml.SysMLParser（不再依赖 window.sysml）。
 */
export class SysmlEditor extends AbstractEditor {

    /** 当前 SysML 代码内容（不含 fence 标记） */
    private _code: string = '';
    /** 当前图类型（从元数据行解析，默认 BDD） */
    private _diagramType: string = 'BDD';
    /** CodeMirror 6 EditorView 实例 */
    private _cmView: EditorView | null = null;
    /** 图形预览 X6 Graph 实例 */
    private _previewGraph: any = null;
    /** 图形预览容器 DOM */
    private _previewEl: HTMLElement | null = null;
    /** 是否正在显示图形预览 */
    private _previewing: boolean = false;

    constructor(block: HTMLElement, callbacks: EditorCallbacks) {
        super(block, callbacks);
        const raw = block.getAttribute('data-marked') || '';
        const { code, diagramType } = this._parseFence(raw);
        this._code = code;
        this._diagramType = diagramType;
    }

    /**
     * 从 fence block 的 data-marked 中提取 SysML 代码和图类型。
     *
     * 解析规则：
     * - 首行 ` ```sysml ` → 跳过
     * - 末行 ` ``` ` → 跳过
     * - 中间内容为 SysML 源代码
     * - 若代码以 `#!sysml <TYPE>` 开头，提取图类型
     */
    private _parseFence(raw: string): { code: string; diagramType: string } {
        const lines = raw.replace(/\r\n/g, '\n').split('\n');
        while (lines.length > 0 && lines[lines.length - 1].trim() === '') lines.pop();
        if (lines.length === 0) return { code: '', diagramType: 'BDD' };

        let start = 0;
        let end = lines.length;
        if (lines[0].trim().match(/^`{3,}\s*sysml\s*$/i)) start = 1;
        if (end > start && lines[end - 1].trim().match(/^`{3,}\s*$/)) end--;

        const code = lines.slice(start, end).join('\n');

        let diagramType = 'BDD';
        for (const line of lines) {
            const m = line.trim().match(/^#!sysml\s+(\w+)/);
            if (m) { diagramType = m[1].toUpperCase(); break; }
        }
        return { code, diagramType };
    }

    /** 创建编辑器容器 div */
    protected _createEditor(): HTMLElement {
        const container = document.createElement('div');
        container.className = 'sysml-editor-cm';
        container.style.cssText = 'position:relative;';
        return container;
    }

    open(): void {
        super.open();
        this._createToolbar();
        this._mountCM6(this._code);
        this._cmView!.focus();
    }

    /**
     * 创建工具栏控件：
     * - 语言标签 "sysml"
     * - 图类型选择下拉框
     * - 预览切换按钮
     */
    private _createToolbar(): void {
        // 语言标签
        const langBadge = document.createElement('span');
        langBadge.textContent = 'sysml';
        langBadge.style.cssText = 'padding:2px 6px;background:#e3f2fd;color:#1565c0;border-radius:4px;font-size:12px;font-weight:bold;margin-right:4px;';
        this._toolbar.appendChild(langBadge);

        // 图类型选择下拉框
        const typeSelect = document.createElement('select');
        typeSelect.style.cssText = 'padding:2px 4px;border:1px solid #90caf9;border-radius:4px;font-size:12px;background:#fff;margin-right:4px;';
        for (const dt of DIAGRAM_TYPES) {
            const opt = document.createElement('option');
            opt.value = dt;
            opt.textContent = dt;
            if (dt === this._diagramType) opt.selected = true;
            typeSelect.appendChild(opt);
        }
        typeSelect.addEventListener('change', () => {
            this._diagramType = typeSelect.value;
            this._updateMetaLine();
        });
        this._toolbar.appendChild(typeSelect);

        // 预览切换按钮
        const previewBtn = document.createElement('button');
        previewBtn.textContent = '▸ 预览图';
        previewBtn.style.cssText = 'padding:2px 8px;border:1px solid #90caf9;border-radius:4px;font-size:12px;background:#fff;cursor:pointer;';
        previewBtn.addEventListener('click', () => this._togglePreview());
        this._toolbar.appendChild(previewBtn);
    }

    /** 挂载 CodeMirror 6 编辑器 */
    private _mountCM6(code: string): void {
        const self = this;
        this._cmView = new EditorView({
            doc: code,
            extensions: [
                syntaxHighlighting(defaultHighlightStyle),
                lineNumbers(),
                EditorView.lineWrapping,
                keymap.of([
                    { key: 'Escape', run: () => { self.close(); return true; } },
                    { key: 'Ctrl-Enter', run: () => { self.commit(); return true; } },
                    ...defaultKeymap,
                ]),
                EditorView.theme({
                    '&': { maxHeight: '400px', border: '1px solid #90caf9', borderRadius: '6px', fontSize: '13px' },
                    '.cm-scroller': { overflow: 'auto' },
                }),
            ],
            parent: this._editor,
        });
    }

    /**
     * 更新 SysML 元数据行以匹配当前图类型选择。
     */
    private _updateMetaLine(): void {
        if (!this._cmView) return;
        const doc = this._cmView.state.doc;
        const text = doc.toString();
        const lines = text.split('\n');

        let found = false;
        for (let i = 0; i < lines.length; i++) {
            if (lines[i].trim().startsWith('#!sysml')) {
                lines[i] = lines[i].replace(/#!sysml\s+\w+/, `#!sysml ${this._diagramType}`);
                found = true;
                break;
            }
        }
        if (!found) {
            lines.unshift(`#!sysml ${this._diagramType} ""`);
        }

        const newText = lines.join('\n');
        this._cmView.dispatch({ changes: { from: 0, to: doc.length, insert: newText } });
    }

    /** 切换文本/图形预览模式 */
    private _togglePreview(): void {
        if (this._previewing) {
            this._hidePreview();
        } else {
            this._showPreview();
        }
    }

    /** 显示图形预览：使用 sysml.ts 中注册的 X6 形状渲染 SysML 图 */
    private _showPreview(): void {
        const code = this._cmView?.state.doc.toString() ?? '';
        if (!code.trim()) return;

        // 隐藏 CM6，显示预览容器
        if (this._cmView) this._cmView.dom.style.display = 'none';
        this._previewing = true;

        if (!this._previewEl) {
            this._previewEl = document.createElement('div');
            this._previewEl.className = 'sysml-preview-canvas';
            this._previewEl.style.cssText = 'width:100%;min-height:300px;max-height:450px;border:1px solid #90caf9;border-radius:6px;overflow:hidden;background:#fafafa;';
            this._editor.appendChild(this._previewEl);
        }
        this._previewEl.style.display = '';

        // 使用内联导入的 sysml.SysMLParser 解析文本（不再依赖 window.sysml）
        try {
            sysml.ensureSysMLShapes();
            const parser = new sysml.SysMLParser();
            const diagram = parser.parse(code, this._diagramType as any);

            // 创建 X6 Graph 进行渲染（使用 sysml.ts 注册的全局形状）
            this._previewGraph = new X6.Graph({
                container: this._previewEl,
                width: this._previewEl.clientWidth || 600,
                height: 400,
                resizing: false,
                rotating: false,
                panning: { enabled: true, modifiers: 'shift' },
                mousewheel: { enabled: true, modifiers: 'ctrl', minScale: 0.5, maxScale: 2 },
                grid: { size: 10, visible: true },
                interacting: { nodeMovable: false, edgeLabelMovable: false, magnetConnectable: false },
            });
            this._previewGraph.fromJSON(diagram);
            this._previewGraph.zoomToFit({ padding: 20, maxScale: 1.5 });
        } catch (err) {
            this._previewEl.innerHTML = `<div style="padding:16px;color:#c62828;font-size:13px;">预览失败: ${String(err)}</div>`;
        }

        this._updatePreviewButton();
    }

    /** 隐藏图形预览，回到文本编辑 */
    private _hidePreview(): void {
        this._previewing = false;
        if (this._cmView) this._cmView.dom.style.display = '';
        if (this._previewGraph) {
            this._previewGraph.dispose();
            this._previewGraph = null;
        }
        if (this._previewEl) {
            this._previewEl.style.display = 'none';
            this._previewEl.innerHTML = '';
        }
        this._updatePreviewButton();
    }

    /** 更新预览按钮文本 */
    private _updatePreviewButton(): void {
        const btn = this._toolbar.querySelector('button');
        if (btn) btn.textContent = this._previewing ? '▸ 文本' : '▸ 预览图';
    }

    /**
     * 收集提交数据。
     *
     * @returns `raw`  — ````sysml\n...\n````` 格式的完整 fence block
     *          `html` — 渲染后的 HTML（含语法高亮占位）
     */
    protected _commitCollect(): { raw: string; html: string } {
        const code = this._cmView?.state.doc.toString() ?? '';
        const raw = '```sysml\n' + code + '\n```';
        const html = AbstractEditor.highlight('sysml', code);
        return { raw, html };
    }

    /** 销毁 CM6 视图和 X6 Graph 实例 */
    protected _destroyEditor(): void {
        this._cmView?.destroy();
        this._cmView = null;
        if (this._previewGraph) {
            this._previewGraph.dispose();
            this._previewGraph = null;
        }
        if (this._previewEl) {
            this._previewEl.innerHTML = '';
            this._previewEl = null;
        }
    }
}
